SELECT c.*, u.real_name AS teacher_name, (SELECT COUNT(*) FROM course_student cs WHERE cs.course_id = c.id) AS student_count FROM course c LEFT JOIN user u ON c.teacher_id = u.id WHERE 1=1 AND c.teacher_id = #{teacherId}
AND (c.name LIKE CONCAT('%', #{keyword}, '%') OR c.code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.created_at DESC
